5518	// resolveRouteBounded runs resolveRoute under a route-resolution deadline. The
5519	// resolver is invoked in a goroutine and selected against the deadline so a
5520	// resolver that ignores context cancellation cannot wedge the single-threaded
5521	// worker past the timeout (the hang observed in ddx-8f2e0ebf). timedOut is true
5522	// only when the deadline fired before the resolver returned; a parent-context
5523	// cancellation reports timedOut=false.
5524	func resolveRouteBounded(
5525		ctx context.Context,
5526		timeout time.Duration,
5527		resolveRoute func(ctx context.Context, req agentlib.RouteRequest) (*agentlib.RouteDecision, error),
5528		req agentlib.RouteRequest,
5529	) (decision *agentlib.RouteDecision, err error, timedOut bool) {
5530		tctx, cancel := context.WithTimeout(ctx, timeout)
5531		defer cancel()
5532		type routeResult struct {
5533			decision *agentlib.RouteDecision
5534			err      error
5535		}
5536		done := make(chan routeResult, 1)
5537		go func() {
5538			d, e := resolveRoute(tctx, req)
5539			done <- routeResult{decision: d, err: e}
5540		}()
5541		select {
5542		case res := <-done:
5543			return res.decision, res.err, false
5544		case <-tctx.Done():
5545			return nil, tctx.Err(), errors.Is(tctx.Err(), context.DeadlineExceeded)
5546		}
5547	}
