5549	// runRoutePreflightBounded runs fn under a route-resolution deadline, returning
5550	// timedOut=true only when the deadline fired before fn returned. fn runs in a
5551	// goroutine so a preflight resolver that ignores context cancellation cannot
5552	// wedge the worker past the timeout.
5553	func runRoutePreflightBounded(ctx context.Context, timeout time.Duration, fn func(ctx context.Context) error) (err error, timedOut bool) {
5554		tctx, cancel := context.WithTimeout(ctx, timeout)
5555		defer cancel()
5556		done := make(chan error, 1)
5557		go func() { done <- fn(tctx) }()
5558		select {
5559		case e := <-done:
5560			return e, false
5561		case <-tctx.Done():
5562			return tctx.Err(), errors.Is(tctx.Err(), context.DeadlineExceeded)
5563		}
5564	}
