153	// RunExternalCloseWatcher runs the external-close watcher until ctx is cancelled
154	// or the watched bead is observed closed. On close it invokes cfg.OnClosed once
155	// and returns. It is intended to run as a goroutine alongside WithHeartbeat.
156	func RunExternalCloseWatcher(ctx context.Context, interval time.Duration, cfg ExternalCloseWatcherConfig) {
157		if interval <= 0 {
158			return
159		}
160		ticker := time.NewTicker(interval)
161		defer ticker.Stop()
162		runExternalCloseWatcher(ctx, ticker.C, cfg)
163	}
164	
165	// runExternalCloseWatcher is the injectable variant used by tests to supply a
166	// stub tick channel.
167	func runExternalCloseWatcher(ctx context.Context, tickCh <-chan time.Time, cfg ExternalCloseWatcherConfig) {
168		for {
169			select {
170			case <-ctx.Done():
171				return
172			case <-tickCh:
173				if cfg.IsClosed == nil {
174					continue
175				}
176				closed, err := cfg.IsClosed()
