2909			if parking := attemptOut.Parking; parking != nil {
2910				if parking.Unclaim {
2911					if err := w.Store.Unclaim(candidate.ID); err != nil {
2912						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
2913							return commitOutcomeError("Unclaim", assignee, result, err)
2914						})
2915						if ctx.Err() != nil {
2916							return result, ctx.Err()
2917						}
2918						continue
2919					}
2920				}
2921				if parking.RunPostAttemptTriage {
2922					report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
2923				}
2924				if parking.Event != nil {
2925					_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
2926						Kind:      parking.Event.Kind,
2927						Summary:   parking.Event.Summary,
2928						Body:      parking.Event.Body,
2929						Actor:     assignee,
2930						Source:    "ddx work",
2931						CreatedAt: now().UTC(),
2932					})
2933				}
2934				if !parking.RetryAfter.IsZero() {
2935					if err := w.Store.SetExecutionCooldown(candidate.ID, parking.RetryAfter, report.Status, report.Detail, report.BaseRev); err != nil {
2936						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
2937							return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
2938						})
2939						if ctx.Err() != nil {
2940							return result, ctx.Err()
2941						}
2942						continue
2943					}
2944					report.RetryAfter = parking.RetryAfter.Format(time.RFC3339)
2945				}
2946			}
2947	
2948			if attemptOut.Disposition == agenttry.OutcomeSuccess {
2949				finalizationCtx := context.Background()
2950				if err := clearExecuteLoopNoChangesMetadata(finalizationCtx, w.Store, candidate.ID); err != nil {
2951					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
2952						return commitOutcomeError("clearExecuteLoopNoChangesMetadata", assignee, result, err)
2953					})
2954					if ctx.Err() != nil {
2955						return result, ctx.Err()
2956					}
2957					continue
2958				}
2959				result.Successes++
2960				result.LastSuccessAt = now().UTC()
2961			} else if report.Status == ExecuteBeadStatusSuccess {
2962				finalizationCtx := context.Background()
2963				if err := clearExecuteLoopNoChangesMetadata(finalizationCtx, w.Store, candidate.ID); err != nil {
2964					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
2965						return commitOutcomeError("clearExecuteLoopNoChangesMetadata", assignee, result, err)
2966					})
2967					if ctx.Err() != nil {
2968						return result, ctx.Err()
2969					}
2970					continue
2971				}
2972				appendLoopRoutingEvidence(w.Store, candidate, report, now().UTC(), readFailedRoutes(candidate.Extra))
2973				// Story 15: when an operator-prompt bead succeeds, scan
2974				// base..result for affected beads and artifacts, and append
2975				// origin_operator_prompt_id back-link events. Failure is
2976				// logged but does not fail the attempt — the bead's own
2977				// commit has already landed and the audit data is best-effort.
2978				if candidate.IssueType == bead.IssueTypeOperatorPrompt {
2979					affected, affErr := computeOperatorPromptAffected(runtime.ProjectRoot, report.BaseRev, report.ResultRev, candidate.ID)
2980					if affErr != nil {
2981						if runtime.Log != nil {
2982							_, _ = fmt.Fprintf(runtime.Log, "operator-prompt backlinks scan: %v\n", affErr)
2983						}
2984					} else if recErr := recordOperatorPromptBacklinks(w.Store, candidate.ID, affected, assignee, now().UTC()); recErr != nil {
2985						if runtime.Log != nil {
2986							_, _ = fmt.Fprintf(runtime.Log, "operator-prompt backlinks: %v\n", recErr)
2987						}
2988					}
2989				}
2990				// Advisory prose-check evidence for docs-changing attempts. Runs
2991				// before CloseWithEvidence so findings land in the bead's history
2992				// while the attempt is still editable. Errors are advisory.
2993				if runtime.ProseEvidenceHook != nil {
2994					if proseErr := runtime.ProseEvidenceHook(ctx, candidate.ID, report); proseErr != nil && runtime.Log != nil {
2995						_, _ = fmt.Fprintf(runtime.Log, "prose evidence: %v (continuing)\n", proseErr)
2996					}
2997				}
2998				// Automated close eligibility is now owned by the pre-land
2999				// candidate-cycle reviewer. The old post-land/pre-close reviewer
3000				// remains available only through an explicit runtime opt-in.
3001				if runtime.PostMergeReview {
3002					reviewOut := RunPostMergeReview(ctx, PostMergeReviewInput{
3003						Bead:          candidate,
3004						Report:        report,
3005						Reviewer:      w.Reviewer,
3006						Store:         w.Store,
3007						ProjectRoot:   runtime.ProjectRoot,
3008						Rcfg:          rcfg,
3009						NoReview:      runtime.NoReview,
3010						Log:           runtime.Log,
3011						Assignee:      assignee,
3012						Now:           now,
3013						ReviewCostCap: runtime.ReviewCostCap,
3014					})
3015					report = reviewOut.Report
3016					if reviewOut.StoreErr != nil {
3017						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
3018							return commitOutcomeError(reviewOut.StoreErrOp, assignee, result, reviewOut.StoreErr)
3019						})
3020						if ctx.Err() != nil {
3021							return result, ctx.Err()
3022						}
3023						continue
3024					}
3025					if reviewOut.Approved {
3026						result.Successes++
3027						result.LastSuccessAt = now().UTC()
3028					} else {
3029						result.Failures++
3030						result.LastFailureStatus = report.Status
3031					}
3032				} else {
3033					if err := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.ResultRev); err != nil {
3034						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
3035							return commitOutcomeError("CloseWithEvidence", assignee, result, err)
3036						})
3037						if ctx.Err() != nil {
3038							return result, ctx.Err()
3039						}
3040						continue
3041					}
3042					result.Successes++
3043					result.LastSuccessAt = now().UTC()
3044				}
3045			} else if attemptOut.Disposition == agenttry.OutcomePark {
3046				result.Failures++
3047				result.LastFailureStatus = report.Status
3048			} else if attemptOut.NoChanges != nil {
3049				noChanges := attemptOut.NoChanges
3050				if err := w.Store.Unclaim(candidate.ID); err != nil {
3051					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
3052						return commitOutcomeError("Unclaim", assignee, result, err)
3053					})
3054					if ctx.Err() != nil {
3055						return result, ctx.Err()
3056					}
3057					continue
3058				}
3059	
3060				// Post-attempt orchestrator decomposition: when the implementation
3061				// attempt signals orchestrator_action: decompose (because it hit the
3062				// implementation depth cap or the bead is too large for the worktree),
3063				// invoke the queue-level splitter. The orchestrator checks the
3064				// queue-level max_decomposition_depth, not the implementation cap.
3065				if report.NoChangesRationale != "" && runtime.PostAttemptDecompositionHook != nil {
3066					parsed := ParseNoChangesRationale(report.NoChangesRationale)
3067					if parsed.OrchestratorAction == "decompose" {
3068						w.handlePostAttemptDecomposition(ctx, &candidate, runtime, assignee, rcfg, now().UTC())
3069						result.Failures++
3070						result.LastFailureStatus = report.Status
3071						continue
3072					}
3073				}
3074	
3075				if noChanges.EventKind != "" {
3076					_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
3077						Kind:      noChanges.EventKind,
3078						Summary:   noChanges.EventKind,
3079						Body:      noChanges.EventBody,
3080						Actor:     assignee,
3081						Source:    "ddx work",
3082						CreatedAt: now().UTC(),
3083					})
3084				}
3085				if noChanges.Label != "" {
3086					if err := addBeadLabel(ctx, w.Store, candidate.ID, noChanges.Label); err != nil {
3087						_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
3088							return commitOutcomeError("addBeadLabel", assignee, result, err)
3089						})
3090						if ctx.Err() != nil {
3091							return result, ctx.Err()
3092						}
3093						continue
3094					}
3095				}

