120	// NewTestConfigForBead returns a *Config that, when Resolve()d with
121	// the matching CLIOverrides, produces a ResolvedConfig whose
122	// execute-bead-relevant accessors return the values supplied in opts.
123	// Pure CLI-override fields (Provider, Effort) have no durable home on
124	// AgentConfig and must be applied at Resolve time via CLIOverrides.
125	func NewTestConfigForBead(opts TestBeadConfigOpts) *Config {
126		cfg := &Config{
127			Version: "1.0",
128			Agent: &AgentConfig{
129				Model: opts.Model,
130			},
131		}
132		if opts.Mirror != nil {
133			cfg.Executions = &ExecutionsConfig{Mirror: opts.Mirror}
134		}
135		return cfg
136	}
