138	// TestBeadOverrides returns the CLIOverrides that, combined with the
139	// *Config produced by NewTestConfigForBead(opts), drive a Resolve call
140	// to a ResolvedConfig matching opts. Pure-override fields (Provider,
141	// Effort) have no durable home on *Config; they are applied at Resolve
142	// time only.
143	func TestBeadOverrides(opts TestBeadConfigOpts) CLIOverrides {
144		return CLIOverrides{
145			Harness:  opts.Harness,
146			Provider: opts.Provider,
147			Effort:   opts.Effort,
148		}
149	}
150	
151	// TestLoopOverrides returns the CLIOverrides that, combined with the
152	// *Config produced by NewTestConfigForLoop(opts), drive a Resolve call
153	// to a ResolvedConfig matching opts. Pure-override fields (Assignee,
154	// Profile) have no durable home on *Config; they are applied at Resolve time only.
155	func TestLoopOverrides(opts TestLoopConfigOpts) CLIOverrides {
156		return CLIOverrides{
157			Assignee: opts.Assignee,
158			Harness:  opts.Harness,
159			Profile:  opts.Profile,
160		}
