5589		tctx, cancel := context.WithTimeout(ctx, timeout)
5590		defer cancel()
5591		type routeResult struct {
5592			decision *agentlib.RouteDecision
5593			err      error
5594		}
5595		done := make(chan routeResult, 1)
5596		go func() {
5597			d, e := resolveRoute(tctx, req)
5598			done <- routeResult{decision: d, err: e}
5599		}()
5600		select {
5601		case res := <-done:
5602			if terr := tctx.Err(); terr != nil {
5603				if errors.Is(terr, context.DeadlineExceeded) {
5604					return nil, terr, true
5605				}
5606				return nil, terr, false
5607			}
5608			return res.decision, res.err, false
5609		case <-tctx.Done():
5610			if terr := tctx.Err(); terr != nil {
5611				return nil, terr, errors.Is(terr, context.DeadlineExceeded)
5612			}
5613			return nil, tctx.Err(), false
5614		}
5615	}
