+// runPostCommitStepBounded runs a post-commit review or close step under a
+// deadline so a hung reviewer or close operation cannot wedge the worker
+// indefinitely. The step runs in a goroutine to mirror the route
+// preflight / resolveRoute bounded helpers; callers decide how to react when the
+// deadline fires.
+func runPostCommitStepBounded(
+	ctx context.Context,
+	timeout time.Duration,
+	fn func(ctx context.Context) error,
+) (timedOut bool, err error) {
+	tctx, cancel := context.WithTimeout(ctx, timeout)
+	defer cancel()
+	done := make(chan error, 1)
+	go func() { done <- fn(tctx) }()
+	select {
+	case err := <-done:
+		if terr := tctx.Err(); terr != nil {
+			if errors.Is(terr, context.DeadlineExceeded) {
+				return true, nil
+			}
+			return false, terr
+		}
+		return false, err
+	case <-tctx.Done():
+		if terr := tctx.Err(); terr != nil {
+			return errors.Is(terr, context.DeadlineExceeded), terr
+		}
+		return false, tctx.Err()
 	}
 }

